int ASN1C_CGI::DecodeFrom (OSRTMessageBufferIF& msgBuf, OSBOOL free)
{
   int stat = setMsgBuf (msgBuf, TRUE);
   if (stat != 0) return (stat);

   asn1Init_CGI (&msgData, free, getCtxtPtr());
   msgData.setContext (msgBuf.getContext());
   if (msgBuf.isA (OSRTMessageBufferIF::PERDecode)) {
      stat = asn1PD_CGI (msgBuf.getCtxtPtr(), &msgData);
      ((ASN1PERDecodeBuffer&)msgBuf).byteAlign();
      return stat;
   }
   else if (msgBuf.isA (OSRTMessageBufferIF::JSONDecode)) {
      return asn1JsonDec_CGI (msgBuf.getCtxtPtr(), &msgData);
   }
   return RTERR_NOTSUPP;
}

int asn1Init_CGI (ASN1T_CGI* pvalue, OSBOOL free, OSCTXT *pctxt)
{
   if (0 == pvalue) return RTERR_NULLPTR;
   if (free) {
      asn1Free_CGI (pctxt, pvalue);
   }
   else {
      pvalue->t = 0;
      OSCRTLMEMSET (&pvalue->u, 0, sizeof(pvalue->u));
   }
   return 0;
}

void asn1Free_CGI (OSCTXT *pctxt, ASN1T_CGI* pvalue)
{
   if (0 == pvalue) return;
   switch (pvalue->t) {
      case 0: break; /* no choice; nothing to free */
      case 1:
         if (0 != pvalue->u.nR_CGI) {
            asn1Free_NR_CGI (pctxt, pvalue->u.nR_CGI);
            ((ASN1T_NR_CGI*)pvalue->u.nR_CGI)->~ASN1T_NR_CGI();
            rtxMemFreePtr (pctxt, (void*)pvalue->u.nR_CGI);
            pvalue->u.nR_CGI = 0;
         }
         break;

      case 2:
         if (0 != pvalue->u.eUTRA_CGI) {
            asn1Free_EUTRA_CGI (pctxt, pvalue->u.eUTRA_CGI);
            ((ASN1T_EUTRA_CGI*)pvalue->u.eUTRA_CGI)->~ASN1T_EUTRA_CGI();
            rtxMemFreePtr (pctxt, (void*)pvalue->u.eUTRA_CGI);
            pvalue->u.eUTRA_CGI = 0;
         }
         break;

      default:
         if (0 != pvalue->u.extElem1) {
            if (!rtxCtxtTestFlag (pctxt, ASN1FASTCOPY)) {
               rtxMemFreePtr (pctxt, (void*)pvalue->u.extElem1->data);
               pvalue->u.extElem1->data = 0;
            }
            rtxMemFreePtr (pctxt, (void*)pvalue->u.extElem1);
            pvalue->u.extElem1 = 0;
         }
   }
}

void ASN1C_CGI::MemFree ()
{
   asn1Free_CGI (getCtxtPtr(), &msgData);
}

