int asn1Init_UEID (ASN1T_UEID* pvalue, OSBOOL free, OSCTXT *pctxt)
{
   if (0 == pvalue) return RTERR_NULLPTR;
   if (free) {
      asn1Free_UEID (pctxt, pvalue);
   }
   else {
      pvalue->t = 0;
      OSCRTLMEMSET (&pvalue->u, 0, sizeof(pvalue->u));
   }
   return 0;
}

void asn1Free_UEID (OSCTXT *pctxt, ASN1T_UEID* pvalue)
{
   if (0 == pvalue) return;
   switch (pvalue->t) {
      case 0: break; /* no choice; nothing to free */
      case 1:
         if (0 != pvalue->u.gNB_UEID) {
            asn1Free_UEID_GNB (pctxt, pvalue->u.gNB_UEID);
            ((ASN1T_UEID_GNB*)pvalue->u.gNB_UEID)->~ASN1T_UEID_GNB();
            rtxMemFreePtr (pctxt, (void*)pvalue->u.gNB_UEID);
            pvalue->u.gNB_UEID = 0;
         }
         break;

      case 2:
         if (0 != pvalue->u.gNB_DU_UEID) {
            asn1Free_UEID_GNB_DU (pctxt, pvalue->u.gNB_DU_UEID);
            ((ASN1T_UEID_GNB_DU*)pvalue->u.gNB_DU_UEID)->~ASN1T_UEID_GNB_DU();
            rtxMemFreePtr (pctxt, (void*)pvalue->u.gNB_DU_UEID);
            pvalue->u.gNB_DU_UEID = 0;
         }
         break;

      case 3:
         if (0 != pvalue->u.gNB_CU_UP_UEID) {
            asn1Free_UEID_GNB_CU_UP (pctxt, pvalue->u.gNB_CU_UP_UEID);
            ((ASN1T_UEID_GNB_CU_UP*)pvalue->u.gNB_CU_UP_UEID)->~ASN1T_UEID_GNB_CU_UP();
            rtxMemFreePtr (pctxt, (void*)pvalue->u.gNB_CU_UP_UEID);
            pvalue->u.gNB_CU_UP_UEID = 0;
         }
         break;

      case 4:
         if (0 != pvalue->u.ng_eNB_UEID) {
            asn1Free_UEID_NG_ENB (pctxt, pvalue->u.ng_eNB_UEID);
            ((ASN1T_UEID_NG_ENB*)pvalue->u.ng_eNB_UEID)->~ASN1T_UEID_NG_ENB();
            rtxMemFreePtr (pctxt, (void*)pvalue->u.ng_eNB_UEID);
            pvalue->u.ng_eNB_UEID = 0;
         }
         break;

      case 5:
         if (0 != pvalue->u.ng_eNB_DU_UEID) {
            asn1Free_UEID_NG_ENB_DU (pctxt, pvalue->u.ng_eNB_DU_UEID);
            ((ASN1T_UEID_NG_ENB_DU*)pvalue->u.ng_eNB_DU_UEID)->~ASN1T_UEID_NG_ENB_DU();
            rtxMemFreePtr (pctxt, (void*)pvalue->u.ng_eNB_DU_UEID);
            pvalue->u.ng_eNB_DU_UEID = 0;
         }
         break;

      case 6:
         if (0 != pvalue->u.en_gNB_UEID) {
            asn1Free_UEID_EN_GNB (pctxt, pvalue->u.en_gNB_UEID);
            ((ASN1T_UEID_EN_GNB*)pvalue->u.en_gNB_UEID)->~ASN1T_UEID_EN_GNB();
            rtxMemFreePtr (pctxt, (void*)pvalue->u.en_gNB_UEID);
            pvalue->u.en_gNB_UEID = 0;
         }
         break;

      case 7:
         if (0 != pvalue->u.eNB_UEID) {
            asn1Free_UEID_ENB (pctxt, pvalue->u.eNB_UEID);
            ((ASN1T_UEID_ENB*)pvalue->u.eNB_UEID)->~ASN1T_UEID_ENB();
            rtxMemFreePtr (pctxt, (void*)pvalue->u.eNB_UEID);
            pvalue->u.eNB_UEID = 0;
         }
         break;

      default:
         if (0 != pvalue->u.extElem1) {
            if (!rtxCtxtTestFlag (pctxt, ASN1FASTCOPY)) {
               rtxMemFreePtr (pctxt, (void*)pvalue->u.extElem1->data);
               pvalue->u.extElem1->data = 0;
            }
            rtxMemFreePtr (pctxt, (void*)pvalue->u.extElem1);
            pvalue->u.extElem1 = 0;
         }
   }
}

