int asn1Init_CoreCPID (ASN1T_CoreCPID* pvalue, OSBOOL free, OSCTXT *pctxt)
{
   if (0 == pvalue) return RTERR_NULLPTR;
   if (free) {
      asn1Free_CoreCPID (pctxt, pvalue);
   }
   else {
      pvalue->t = 0;
      OSCRTLMEMSET (&pvalue->u, 0, sizeof(pvalue->u));
   }
   return 0;
}

void asn1Free_CoreCPID (OSCTXT *pctxt, ASN1T_CoreCPID* pvalue)
{
   if (0 == pvalue) return;
   switch (pvalue->t) {
      case 0: break; /* no choice; nothing to free */
      case 1:
         if (0 != pvalue->u.fiveGC) {
            asn1Free_GUAMI (pctxt, pvalue->u.fiveGC);
            ((ASN1T_GUAMI*)pvalue->u.fiveGC)->~ASN1T_GUAMI();
            rtxMemFreePtr (pctxt, (void*)pvalue->u.fiveGC);
            pvalue->u.fiveGC = 0;
         }
         break;

      case 2:
         if (0 != pvalue->u.ePC) {
            asn1Free_GUMMEI (pctxt, pvalue->u.ePC);
            ((ASN1T_GUMMEI*)pvalue->u.ePC)->~ASN1T_GUMMEI();
            rtxMemFreePtr (pctxt, (void*)pvalue->u.ePC);
            pvalue->u.ePC = 0;
         }
         break;

      default:
         if (0 != pvalue->u.extElem1) {
            if (!rtxCtxtTestFlag (pctxt, ASN1FASTCOPY)) {
               rtxMemFreePtr (pctxt, (void*)pvalue->u.extElem1->data);
               pvalue->u.extElem1->data = 0;
            }
            rtxMemFreePtr (pctxt, (void*)pvalue->u.extElem1);
            pvalue->u.extElem1 = 0;
         }
   }
}

